INSERT INTO `posts` (`id`, `user_id`, `category_id`, `title`, `slug`, `excerpt`, `content`, `featured_image`, `status`, `is_featured`, `allow_comments`, `views`, `published_at`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 1, 2, 'Cambodia Real Estate Market Outlook 2025', 'cambodia-real-estate-market-outlook-2025', 'A comprehensive analysis of the Cambodia real estate market trends and predictions for 2025.', '<h2>Market Overview</h2><p>The Cambodia real estate market continues to show strong growth potential heading into 2025. With increased foreign investment and infrastructure development, property values in key areas are expected to rise steadily.</p><h3>Key Trends</h3><ul><li>Increased demand for luxury condominiums in Phnom Penh</li><li>Growing interest in Sihanoukville coastal properties</li><li>Expansion of borey developments in suburban areas</li></ul><p>Investors are particularly interested in mixed-use developments that combine residential and commercial spaces.</p>', NULL, 'published', 1, 1, 4888, '2025-12-04 08:15:00', '2025-12-05 08:15:38', '2025-12-05 09:05:06', NULL),
(2, 1, 3, 'Top 5 Investment Hotspots in Phnom Penh', 'top-5-investment-hotspots-in-phnom-penh', 'Discover the most promising areas for real estate investment in Cambodia\'s capital city.', '<h2>Investment Opportunities</h2><p>Phnom Penh offers numerous investment opportunities for both local and foreign investors. Here are the top 5 areas to consider:</p><h3>1. BKK1 (Boeung Keng Kang 1)</h3><p>The most prestigious residential area with high rental yields.</p><h3>2. Toul Kork</h3><p>Emerging as a popular choice for families and expats.</p><h3>3. Chroy Changvar</h3><p>Rapidly developing with new infrastructure projects.</p><h3>4. Sen Sok</h3><p>Affordable options with growing amenities.</p><h3>5. Chamkarmon</h3><p>Central location with commercial potential.</p>', NULL, 'published', 1, 1, 224, '2025-11-13 08:15:00', '2025-12-05 08:15:38', '2025-12-05 09:18:34', NULL),
(3, 1, 4, 'Guide to Buying Property in Cambodia as a Foreigner', 'guide-to-buying-property-in-cambodia-as-a-foreigner', 'Everything you need to know about property ownership laws and processes for foreign buyers.', '<h2>Foreign Ownership in Cambodia</h2><p>While foreigners cannot directly own land in Cambodia, there are legal structures that allow foreign investment in property.</p><h3>Options for Foreign Buyers</h3><ul><li>Strata title ownership (condos above ground floor)</li><li>Long-term leases (up to 50 years, renewable)</li><li>Company structure ownership</li></ul><h3>Legal Requirements</h3><p>It is essential to work with a reputable lawyer and real estate agent when purchasing property in Cambodia.</p>', NULL, 'published', 0, 1, 2711, '2025-11-22 08:15:00', '2025-12-05 08:15:38', '2025-12-05 09:18:42', NULL),
(4, 1, 6, 'New Luxury Condo Development Launches in BKK1', 'new-luxury-condo-development-launches-in-bkk1', 'A world-class condominium project has been announced in the heart of Phnom Penh.', '<h2>Project Announcement</h2><p>A new luxury condominium development has been announced in the prestigious BKK1 district. The project features world-class amenities and stunning city views.</p><h3>Project Features</h3><ul><li>Sky pool and fitness center</li><li>24/7 security and concierge</li><li>Underground parking</li><li>Smart home technology</li></ul><p>Pre-sales are expected to begin next month with attractive early bird discounts.</p>', NULL, 'published', 1, 1, 3438, '2025-11-11 08:15:00', '2025-12-05 08:15:38', '2025-12-05 09:18:53', NULL),
(5, 1, 1, 'Sihanoukville Property Market Recovery', 'sihanoukville-property-market-recovery', 'The coastal city shows signs of recovery with new investment flowing in.', '<h2>Market Recovery</h2><p>After a period of adjustment, Sihanoukville\'s property market is showing strong signs of recovery. New regulations and improved infrastructure are attracting quality investments.</p><h3>Key Developments</h3><ul><li>New international airport expansion</li><li>Improved road connectivity</li><li>Sustainable tourism initiatives</li></ul><p>Beach-front properties and resort developments are particularly in demand.</p>', NULL, 'published', 0, 1, 4917, '2025-11-28 08:15:00', '2025-12-05 08:15:38', '2025-12-05 09:19:01', NULL),
(6, 1, 8, 'Understanding Property Taxes in Cambodia', 'understanding-property-taxes-in-cambodia', 'A complete guide to property taxes and fees for property owners in Cambodia.', '<h2>Property Tax Guide</h2><p>Understanding the tax obligations for property ownership in Cambodia is essential for all investors.</p><h3>Types of Property Taxes</h3><ul><li>Property tax: 0.1% of assessed value annually</li><li>Transfer tax: 4% of sale price</li><li>Rental income tax: Progressive rates</li></ul><h3>Tax Exemptions</h3><p>Properties valued below a certain threshold may be exempt from annual property tax.</p>', NULL, 'published', 0, 1, 3169, '2025-12-03 08:15:00', '2025-12-05 08:15:38', '2025-12-05 09:19:10', NULL),
(7, 1, 7, 'Best Boreys for Family Living in 2025', 'best-boreys-for-family-living-in-2025', 'Top borey developments offering the best value and amenities for families.', '<h2>Family-Friendly Boreys</h2><p>Borey developments continue to be popular choices for families seeking secure and well-planned communities.</p><h3>Top Picks</h3><ul><li>Borey Peng Huoth - Multiple locations with excellent amenities</li><li>Borey Chip Mong - Modern designs and strong security</li><li>Borey Vimean Phnom Penh - Affordable options</li></ul><p>Consider proximity to schools, hospitals, and workplaces when choosing a borey.</p>', NULL, 'published', 1, 1, 4254, '2025-11-11 08:15:00', '2025-12-05 08:15:38', '2025-12-05 09:19:19', NULL),
(8, 1, 1, 'Draft: Upcoming Real Estate Event', 'draft-upcoming-real-estate-event', 'Information about an upcoming real estate exhibition and networking event.', '<h2>Event Details Coming Soon</h2><p>Stay tuned for more information about this exciting real estate event.</p>', NULL, 'draft', 0, 1, 3486, '2025-12-05 16:20:00', '2025-12-05 08:15:38', '2025-12-05 09:21:45', NULL);
