(52, 1, 'Commercial Land with Shophouse Near Russian Market', 'Strategic 500sqm plot with existing shophouse near bustling Russian Market area. High foot traffic location ideal for business or redevelopment. Hard title available.', 'For Sale', 'Land', 950000.00, 'Street 440, Russian Market', 'Phnom Penh', 'Toul Tom Poung', 2, 2, 500.00, 'sqm', NULL, NULL, '\"[\\\"Commercial Area\\\",\\\"High Traffic\\\",\\\"Hard Title\\\",\\\"Near Market\\\"]\"', 0, 1, 2, '2025-11-29 07:36:38', '2025-12-07 05:20:41', NULL),
(53, 1, 'Large Development Land with Farmhouse in Sen Sok', '5 hectares of prime development land with existing structures in rapidly growing Sen Sok district. Perfect for borey development or mixed-use project. Near Ring Road 3.', 'For Sale', 'Land', 4500000.00, 'National Road 5, Sen Sok', 'Phnom Penh', 'Sen Sok', 4, 4, 50000.00, 'sqm', NULL, NULL, '\"[\\\"Large Plot\\\",\\\"Development Zone\\\",\\\"Near Ring Road\\\",\\\"Investment Opportunity\\\"]\"', 1, 1, 0, '2025-11-29 07:36:38', '2025-11-29 07:36:38', NULL),
(54, 1, 'Beachfront Land with Villa in Sihanoukville', 'Pristine 2,000sqm beachfront property with existing beach villa on Otres Beach. Perfect for renovation or resort development. Direct beach access with stunning sunset views.', 'For Sale', 'Land', 1800000.00, 'Otres Beach', 'Sihanoukville', 'Mittapheap', 3, 3, 2000.00, 'sqm', NULL, NULL, '\"[\\\"Beachfront\\\",\\\"Tourism Zone\\\",\\\"Sunset Views\\\",\\\"Resort Potential\\\"]\"', 1, 1, 0, '2025-11-29 07:36:38', '2025-11-29 07:36:38', NULL),
(55, 1, 'Agricultural Land with Farm Villa', '10,000sqm agricultural land with existing farm villa in Kandal province, 15 minutes from Phnom Penh. Suitable for eco-resort development or private estate.', 'For Sale', 'Land', 350000.00, 'Ta Khmao', 'Kandal', 'Ta Khmao', 2, 3, 10000.00, 'sqm', NULL, NULL, '\"[\\\"Agricultural\\\",\\\"Near Capital\\\",\\\"Eco-Tourism Potential\\\",\\\"Peaceful Location\\\"]\"', 0, 1, 0, '2025-11-29 07:36:38', '2025-11-29 07:36:38', NULL),
(56, 1, 'Embassy Quarter Land with Colonial Villa', 'Exclusive 600sqm plot with charming colonial villa in embassy district, BKK3. Surrounded by embassies and high-end residences. Perfect for renovation or redevelopment.', 'For Sale', 'Land', 2100000.00, 'Street 70, BKK3', 'Phnom Penh', 'Chamkarmon', 4, 2, 600.00, 'sqm', NULL, NULL, '[\"Security\"]', 0, 1, 0, '2025-11-29 07:36:38', '2025-12-05 02:55:20', NULL),
(57, 1, 'Riverside Land with Khmer House in Chroy Changvar', '3,000sqm riverside plot with traditional Khmer house overlooking Mekong River. Ideal for luxury resort or residential redevelopment. Growing area with new infrastructure.', 'For Sale', 'Land', 2400000.00, 'Chroy Changvar Bridge Area', 'Phnom Penh', 'Chroy Changvar', 3, 2, 3000.00, 'sqm', NULL, NULL, '\"[\\\"Riverside\\\",\\\"Mekong Views\\\",\\\"Development Area\\\",\\\"Bridge Access\\\"]\"', 1, 1, 0, '2025-11-29 07:36:38', '2025-11-29 07:36:38', NULL),
(58, 1, 'Corner Land with Townhouse in Toul Kork', 'Well-positioned 450sqm corner plot with modern townhouse in developing Toul Kork area. Near schools, hospitals, and shopping. Ready for immediate occupancy or redevelopment.', 'For Sale', 'Land', 675000.00, 'Street 289, Toul Kork', 'Phnom Penh', 'Toul Kork', 2, 4, 450.00, 'sqm', NULL, NULL, '\"[\\\"Corner Plot\\\",\\\"Near Schools\\\",\\\"Residential Zone\\\",\\\"Good Access\\\"]\"', 0, 1, 0, '2025-11-29 07:36:38', '2025-11-29 07:36:38', NULL),
(59, 1, 'Industrial Land with Warehouse Near Airport', '2 hectares industrial land with existing warehouse structure near Phnom Penh International Airport. Perfect for logistics center or manufacturing. All utilities available.', 'For Sale', 'Land', 1600000.00, 'Russian Boulevard', 'Phnom Penh', 'Dangkor', 4, 3, 20000.00, 'sqm', NULL, NULL, '\"[\\\"Industrial Zone\\\",\\\"Near Airport\\\",\\\"Utilities Ready\\\",\\\"Logistics Hub\\\"]\"', 0, 1, 0, '2025-11-29 07:36:38', '2025-11-29 07:36:38', NULL),
(60, 1, 'Boutique Land with Colonial Building in Kampot', '800sqm riverside plot with charming colonial building in Kampot town. Tourism area perfect for boutique hotel conversion or restaurant. Heritage charm with modern potential.', 'For Sale', 'Land', 320000.00, 'Riverside Road', 'Kampot', 'Kampot', 3, 4, 800.00, 'sqm', NULL, NULL, '\"[\\\"Riverside\\\",\\\"Tourism Area\\\",\\\"Colonial Quarter\\\",\\\"Restaurant Potential\\\"]\"', 0, 1, 0, '2025-11-29 07:36:38', '2025-11-29 07:36:38', NULL),
(61, 1, 'Mountain View Land with Sea View Villa in Kep', '5,000sqm hillside land with luxury villa offering panoramic sea and mountain views in Kep. Near National Park, ideal for boutique resort or private estate.', 'For Sale', 'Land', 750000.00, 'Kep Hillside', 'Kep', 'Kep', 2, 2, 5000.00, 'sqm', NULL, NULL, '\"[\\\"Sea Views\\\",\\\"Mountain Views\\\",\\\"Near National Park\\\",\\\"Tourism Zone\\\"]\"', 0, 1, 0, '2025-11-29 07:36:38', '2025-11-29 07:36:38', NULL),
(62, 1, 'Prime Office Building in BKK1 Business District', 'Modern 6-story office building with 2,500sqm total floor area in BKK1 CBD. Currently 85% occupied with stable rental income. Ground floor retail space, ample parking, and excellent corporate tenant mix.', 'For Sale', 'Commercial', 5800000.00, 'Sothearos Boulevard, BKK1', 'Phnom Penh', 'Chamkarmon', 3, 5, 2500.00, 'sqm', NULL, NULL, '[\"Elevator\"]', 1, 1, 0, '2025-11-29 07:36:38', '2025-12-05 02:52:56', NULL),
(63, 1, 'Boutique Hotel Near Russian Market', '28-room boutique hotel in prime tourist area near Russian Market. Fully operational with restaurant, rooftop bar, and spa. Excellent TripAdvisor ratings and established clientele. Turnkey investment opportunity.', 'For Sale', 'Commercial', 3200000.00, 'Street 450, Toul Tom Poung', 'Phnom Penh', 'Toul Tom Poung', 3, 5, 1800.00, 'sqm', NULL, NULL, '\"[\\\"Restaurant\\\",\\\"Rooftop Bar\\\",\\\"Spa\\\",\\\"Fully Furnished\\\",\\\"Operating Business\\\",\\\"Tourist Area\\\"]\"', 1, 1, 0, '2025-11-29 07:36:38', '2025-11-29 07:36:38', NULL),
(64, 1, 'Retail Shopping Complex on Monivong Boulevard', 'Three-story retail complex with 15 shop units on busy Monivong Boulevard. High foot traffic location with established tenants including banks, cafes, and retail stores. Parking for 50 vehicles.', 'For Sale', 'Commercial', 4500000.00, 'Monivong Boulevard', 'Phnom Penh', 'Daun Penh', 3, 6, 3200.00, 'sqm', NULL, NULL, '\"[\\\"Multiple Units\\\",\\\"High Traffic\\\",\\\"Parking Lot\\\",\\\"Established Tenants\\\",\\\"Main Road\\\",\\\"Investment Property\\\"]\"', 0, 1, 0, '2025-11-29 07:36:38', '2025-11-29 07:36:38', NULL),
(65, 1, 'Modern Warehouse Near Phnom Penh Port', 'Large 4,000sqm warehouse facility with office space near Phnom Penh Autonomous Port. High ceilings, loading docks, 24/7 security. Ideal for logistics, distribution, or light manufacturing.', 'For Sale', 'Commercial', 2800000.00, 'Street 217, Dangkor', 'Phnom Penh', 'Dangkor', 2, 4, 4000.00, 'sqm', NULL, NULL, '\"[\\\"Loading Docks\\\",\\\"High Ceilings\\\",\\\"Office Space\\\",\\\"Security System\\\",\\\"Near Port\\\",\\\"Industrial Zone\\\"]\"', 0, 1, 0, '2025-11-29 07:36:38', '2025-11-29 07:36:38', NULL),
(66, 1, 'Mixed-Use Building in Riverside Tourist Quarter', 'Prime riverside location with restaurant on ground floor, guesthouse rooms above, and rooftop bar with Mekong views. Fully licensed and operational. Perfect for hospitality investment in tourist hotspot.', 'For Sale', 'Commercial', 2400000.00, 'Sisowath Quay', 'Phnom Penh', 'Daun Penh', 3, 5, 850.00, 'sqm', NULL, NULL, '\"[\\\"Riverside\\\",\\\"Restaurant\\\",\\\"Guesthouse\\\",\\\"Rooftop Bar\\\",\\\"Tourist Area\\\",\\\"River Views\\\"]\"', 1, 1, 0, '2025-11-29 07:36:38', '2025-11-29 07:36:38', NULL),
(67, 1, 'Modern Corner Townhouse in Borey Peng Huoth', 'Beautiful 3-story corner townhouse in prestigious gated community. Features 4 spacious bedrooms, modern kitchen with island, private rooftop terrace, and covered parking for 2 cars. 24/7 security and community amenities.', 'For Sale', 'Commercial', 285000.00, 'Borey Peng Huoth, Street 371', 'Phnom Penh', 'Chamkarmon', 4, 3, 220.00, 'sqm', NULL, NULL, '[\"Parking\"]', 1, 1, 0, '2025-11-29 07:36:38', '2025-12-05 02:42:38', NULL),
(68, 1, 'Luxury Twin Villa Near Aeon Mall', 'Stunning twin villa townhouse with contemporary design near Aeon Mall Sen Sok. 3 bedrooms with walk-in closets, open-plan living area, private garden, and smart home features. Perfect for modern families.', 'For Sale', 'Villa', 195000.00, 'Borey Chip Mong Sen Sok', 'Phnom Penh', 'Sen Sok', 3, 4, 180.00, 'sqm', NULL, NULL, '[\"Parking\"]', 0, 1, 0, '2025-11-29 07:36:38', '2025-12-05 02:42:11', NULL),
(69, 1, 'Renovated Shophouse Townhouse in BKK3', 'Beautifully renovated 4-story shophouse converted to modern townhouse. Ground floor suitable for home office, 3 bedrooms upstairs, rooftop entertainment area with city views. Prime BKK3 location.', 'For Sale', 'Villa', 520000.00, 'Street 63, BKK3', 'Phnom Penh', 'Chamkarmon', 3, 3, 240.00, 'sqm', NULL, NULL, '\"[\\\"Home Office\\\",\\\"Rooftop\\\",\\\"City Views\\\",\\\"Renovated\\\",\\\"Prime Location\\\"]\"', 1, 1, 0, '2025-11-29 07:36:38', '2025-12-05 02:41:42', NULL),
(70, 1, 'Family Townhouse in Toul Kork', 'Spacious 2-story townhouse in quiet residential area. Features large living spaces, 4 bedrooms perfect for growing families, maid room, covered parking, and small garden. Close to TK Avenue and schools.', 'For Sale', 'Villa', 165000.00, 'Street 315, Toul Kork', 'Phnom Penh', 'Toul Kork', 4, 2, 150.00, 'sqm', NULL, NULL, '[\"Garden\", \"Parking\"]', 0, 1, 2, '2025-11-29 07:36:38', '2025-12-24 10:14:42', NULL),
(71, 1, 'Executive Townhouse in Diamond Island', 'Premium 3-story townhouse in exclusive Diamond Island development. High-end finishes, 3 bedrooms with ensuite bathrooms, European kitchen, private elevator, and underground parking. Walking distance to Elite Golf Club.', 'For Sale', 'House', 680000.00, 'Koh Pich (Diamond Island)', 'Phnom Penh', 'Tonle Bassac', 3, 4, 280.00, 'sqm', NULL, NULL, '\"[\\\"Private Elevator\\\",\\\"Premium Finishes\\\",\\\"Golf Club Access\\\",\\\"Underground Parking\\\",\\\"River Views\\\"]\"', 1, 1, 0, '2025-11-29 07:36:38', '2025-12-05 02:40:12', NULL),
(72, 1, 'Affordable Townhouse in Chbar Ampov', 'Well-maintained budget-friendly townhouse in developing Chbar Ampov district. 2 spacious bedrooms, open living area, basic kitchen, and space for motorbike parking. Great starter home near National Road 1.', 'For Sale', 'House', 85000.00, 'Borey Piphup Thmey', 'Phnom Penh', 'Chbar Ampov', 2, 2, 120.00, 'sqm', NULL, NULL, '[\"Parking\"]', 0, 1, 5, '2025-11-29 07:36:38', '2025-12-24 10:14:33', NULL),
(73, 1, 'Riverside Townhouse in Chroy Changvar', 'Contemporary 3-bedroom townhouse with Mekong River views. Features modern open-plan design, quality fixtures, balconies on each floor, and rooftop terrace. Part of new riverside community development.', 'For Sale', 'Commercial', 235000.00, 'Chroy Changvar Riverside', 'Phnom Penh', 'Chroy Changvar', 3, 3, 190.00, 'sqm', NULL, NULL, '\"[\\\"River Views\\\",\\\"Multiple Balconies\\\",\\\"Rooftop Terrace\\\",\\\"Modern Design\\\",\\\"New Development\\\"]\"', 0, 1, 4, '2025-11-29 07:36:38', '2025-12-24 10:14:23', NULL),
(74, 1, 'Garden Townhouse in Borey Vimean Phnom Penh', 'Charming townhouse in established borey with mature gardens. 3 bedrooms, spacious living areas, covered carport, and private backyard perfect for family gatherings. Community playground and 24-hour security.', 'For Sale', 'Condo', 178000.00, 'Borey Vimean Phnom Penh, Street 1986', 'Phnom Penh', 'Dangkor', 3, 2, 160.00, 'sqm', NULL, NULL, '[\"Security\"]', 0, 1, 26, '2025-11-29 07:36:38', '2025-12-24 11:15:05', NULL);
