(2329, 'App\\Models\\NewsArticle', 1, 'en', 'title', 'Phnom Penh Property Market Shows Strong Growth in 2025', '2025-11-29 07:36:39', '2025-11-29 07:36:39'),
(2330, 'App\\Models\\NewsArticle', 1, 'en', 'category', 'Market Update', '2025-11-29 07:36:39', '2025-11-29 07:36:39'),
(2331, 'App\\Models\\NewsArticle', 1, 'en', 'excerpt', 'The capital city continues to attract both local and foreign investors with new developments and strong rental yields. Market analysis shows sustained growth across all property types.', '2025-11-29 07:36:39', '2025-11-29 07:36:39'),
(2332, 'App\\Models\\NewsArticle', 1, 'en', 'content', 'The Cambodian real estate market has demonstrated remarkable resilience and growth in 2025, with Phnom Penh leading the charge. According to recent data from the Ministry of Land Management, property transactions have increased by 15% year-over-year, driven by both domestic and international demand.\n\nKey factors contributing to this growth include improved infrastructure, political stability, and attractive investment opportunities. The condominium market has been particularly robust, with average prices in prime locations such as BKK1 and Chamkarmon increasing by 8-10%.\n\nForeign investors, particularly from China, Singapore, and South Korea, continue to show strong interest in Cambodia\'s property market. The recent introduction of new infrastructure projects, including the expressway to Sihanoukville and improvements to Phnom Penh\'s public transport system, have further enhanced the market\'s attractiveness.\n\nReal estate experts predict that this upward trend will continue throughout 2025 and beyond, making now an opportune time for both investment and homeownership.', '2025-11-29 07:36:39', '2025-11-29 07:36:39'),
(2333, 'App\\Models\\NewsArticle', 1, 'km', 'title', 'Phnom Penh Property Market Shows Strong Growth in 2025 (ខ្មែរ)', '2025-11-29 07:36:39', '2025-11-29 07:36:39'),
