(2345, 'App\\Models\\NewsArticle', 2, 'en', 'title', 'New Borey Developments Announced in Sen Sok District', '2025-11-29 07:36:39', '2025-11-29 07:36:39'),
(2346, 'App\\Models\\NewsArticle', 2, 'en', 'category', 'Development', '2025-11-29 07:36:39', '2025-11-29 07:36:39'),
(2347, 'App\\Models\\NewsArticle', 2, 'en', 'excerpt', 'Three major developers have announced plans for new gated communities targeting middle-income families. The projects are expected to deliver over 2,000 units by 2026.', '2025-11-29 07:36:39', '2025-11-29 07:36:39'),
(2348, 'App\\Models\\NewsArticle', 2, 'en', 'content', 'Sen Sok district is set to become one of the fastest-growing residential areas in Phnom Penh with the announcement of three major borey developments by leading property developers.\n\nGlobal Titan Stone, Borey Peng Huoth, and Century Properties have collectively committed to investing over $500 million in these new projects, which will feature modern amenities, green spaces, and family-oriented facilities.\n\nThe developments are strategically located near key infrastructure including schools, hospitals, and the upcoming Ring Road 3, making them highly attractive to young families and first-time homebuyers.\n\n\"These projects address the growing demand for quality, affordable housing in Phnom Penh,\" said Mr. Sok Pheng, CEO of Century Properties. \"We\'re seeing strong pre-launch interest from both local and overseas Cambodian buyers.\"\n\nThe boreys will feature various house types ranging from townhouses to semi-detached villas, with prices starting from $95,000, making homeownership more accessible to the growing middle class.', '2025-11-29 07:36:39', '2025-11-29 07:36:39'),
(2349, 'App\\Models\\NewsArticle', 2, 'km', 'title', 'New Borey Developments Announced in Sen Sok District (ខ្មែរ)', '2025-11-29 07:36:39', '2025-11-29 07:36:39'),
