INSERT INTO `translations` (`id`, `translatable_type`, `translatable_id`, `locale`, `field`, `value`, `created_at`, `updated_at`) VALUES
(2361, 'App\\Models\\NewsArticle', 3, 'en', 'title', 'Condominium Prices Stabilize After Years of Growth', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2362, 'App\\Models\\NewsArticle', 3, 'en', 'category', 'Market Analysis', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2363, 'App\\Models\\NewsArticle', 3, 'en', 'excerpt', 'Industry experts report a cooling period as the market reaches maturity. Average prices remain steady while transaction volumes increase, indicating healthy market conditions.', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2364, 'App\\Models\\NewsArticle', 3, 'en', 'content', 'After several years of rapid price appreciation, Cambodia\'s condominium market is showing signs of maturation and stabilization. According to the latest report by CBRE Cambodia, average condominium prices across Phnom Penh have remained relatively flat over the past six months, marking a shift from the double-digit annual growth seen in previous years.\n\nThis stabilization is viewed positively by industry experts, who suggest it indicates a healthy market correction. \"A sustainable market needs periods of consolidation,\" explains Ms. Linda Chen, Head of Research at CBRE Cambodia. \"What we\'re seeing now is increased transaction activity at stable prices, which is actually more beneficial for long-term market health than continuous rapid appreciation.\"\n\nThe data shows interesting variations across different areas. Prime locations like BKK1 and Diamond Island continue to see slight appreciation of 3-5% annually, while newer development areas are experiencing price stabilization as supply catches up with demand.\n\nRental yields remain attractive, averaging 6-8% in prime locations, which continues to draw investor interest despite the slower capital appreciation. The market is also seeing a shift towards quality over quantity, with buyers increasingly favoring well-managed properties with strong facilities and services.', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2365, 'App\\Models\\NewsArticle', 3, 'km', 'title', 'Condominium Prices Stabilize After Years of Growth (ខ្មែរ)', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2366, 'App\\Models\\NewsArticle', 3, 'km', 'category', 'Market Analysis', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
