(2409, 'App\\Models\\NewsArticle', 6, 'en', 'title', 'Sustainable Building Practices Gain Traction in Cambodia', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2410, 'App\\Models\\NewsArticle', 6, 'en', 'category', 'Development', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2411, 'App\\Models\\NewsArticle', 6, 'en', 'excerpt', 'Developers increasingly adopt green building standards as environmental awareness grows among buyers. First LEED-certified residential project launches in Phnom Penh.', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2412, 'App\\Models\\NewsArticle', 6, 'en', 'content', 'Environmental sustainability is becoming a key consideration in Cambodia\'s real estate sector, with developers increasingly incorporating green building practices into their projects.\n\nThe trend was highlighted by the launch of Green Valley Estates in Toul Kork, which has become the first residential development in Cambodia to achieve LEED (Leadership in Energy and Environmental Design) certification.\n\nThe project features solar panels, rainwater harvesting systems, natural ventilation design, and extensive green spaces. \"Sustainability is not just good for the environment, it\'s also good business,\" explains the project developer. \"We\'re seeing strong demand from buyers who value lower utility costs and healthier living environments.\"\n\nA recent survey by CBRE Cambodia found that 65% of property buyers would pay a premium of 5-10% for properties with verified green features. This growing awareness is driving developers to rethink their approach.\n\nThe government has also shown support for sustainable development, introducing incentives for buildings that meet recognized environmental standards, including faster permit approvals and reduced utility connection fees.\n\nIndustry experts predict that green building practices will become standard rather than exceptional within the next five years, particularly for high-end developments.', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2413, 'App\\Models\\NewsArticle', 6, 'km', 'title', 'Sustainable Building Practices Gain Traction in Cambodia (ខ្មែរ)', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
