(2425, 'App\\Models\\NewsArticle', 7, 'en', 'title', 'Sihanoukville Property Market Rebounds with Tourism Recovery', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2426, 'App\\Models\\NewsArticle', 7, 'en', 'category', 'Market Update', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2427, 'App\\Models\\NewsArticle', 7, 'en', 'excerpt', 'Coastal city sees renewed investor interest as international tourism returns to pre-pandemic levels. Beach-front properties and hospitality sector lead recovery.', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2428, 'App\\Models\\NewsArticle', 7, 'en', 'content', 'Sihanoukville\'s property market is experiencing a significant rebound as international tourism returns to Cambodia\'s premier coastal destination. After several challenging years, the city is witnessing renewed investor confidence and development activity.\n\nTourism statistics from the Ministry of Tourism show that visitor arrivals to Sihanoukville have increased by 85% in 2025 compared to the previous year, with Chinese, Russian, and European tourists leading the recovery. This has directly impacted the local property market, particularly in the hospitality and residential sectors.\n\nBeachfront properties are seeing the strongest demand, with average prices increasing by 12% year-over-year. Several international hotel chains have announced expansion plans, including the development of new five-star resorts along Otres Beach and Independence Beach.\n\n\"The fundamentals are strong again,\" says Mr. Chen Wei, a property analyst specializing in coastal markets. \"Infrastructure improvements, including the expanded airport and improved road connections to Phnom Penh, have made Sihanoukville more accessible than ever.\"\n\nThe rental market is also showing positive signs, with occupancy rates for quality apartments and villas reaching 75%, up from just 40% two years ago. Short-term rental platforms report increasing bookings, suggesting growing confidence in the tourism sector.', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2429, 'App\\Models\\NewsArticle', 7, 'km', 'title', 'Sihanoukville Property Market Rebounds with Tourism Recovery (ខ្មែរ)', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2430, 'App\\Models\\NewsArticle', 7, 'km', 'category', 'Market Update', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2431, 'App\\Models\\NewsArticle', 7, 'km', 'excerpt', 'Coastal city sees renewed investor interest as international tourism returns to pre-pandemic levels. Beach-front properties and hospitality sector lead recovery. [សង្ខេបជាភាសាខ្មែរ]', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2432, 'App\\Models\\NewsArticle', 7, 'km', 'content', 'Sihanoukville\'s property market is experiencing a significant rebound as international tourism returns to Cambodia\'s premier coastal destination. After several challenging years, the city is witnessing renewed investor confidence and development activity.\n\nTourism statistics from the Ministry of Tourism show that visitor arrivals to Sihanoukville have increased by 85% in 2025 compared to the previous year, with Chinese, Russian, and European tourists leading the recovery. This has directly impacted the local property market, particularly in the hospitality and residential sectors.\n\nBeachfront properties are seeing the strongest demand, with average prices increasing by 12% year-over-year. Several international hotel chains have announced expansion plans, including the development of new five-star resorts along Otres Beach and Independence Beach.\n\n\"The fundamentals are strong again,\" says Mr. Chen Wei, a property analyst specializing in coastal markets. \"Infrastructure improvements, including the expanded airport and improved road connections to Phnom Penh, have made Sihanoukville more accessible than ever.\"\n\nThe rental market is also showing positive signs, with occupancy rates for quality apartments and villas reaching 75%, up from just 40% two years ago. Short-term rental platforms report increasing bookings, suggesting growing confidence in the tourism sector.\n\n[មាតិកាពេញលេញជាភាសាខ្មែរ]', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2433, 'App\\Models\\NewsArticle', 7, 'zh', 'title', 'Sihanoukville Property Market Rebounds with Tourism Recovery (中文)', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
