(2473, 'App\\Models\\NewsArticle', 10, 'en', 'title', 'Luxury Villa Market Attracts Ultra-High Net Worth Buyers', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2474, 'App\\Models\\NewsArticle', 10, 'en', 'category', 'Luxury Real Estate', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2475, 'App\\Models\\NewsArticle', 10, 'en', 'excerpt', 'Premium properties in exclusive locations command record prices. International buyers drive demand for luxury estates in Phnom Penh and coastal areas.', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2476, 'App\\Models\\NewsArticle', 10, 'en', 'content', 'Cambodia\'s luxury real estate segment is experiencing unprecedented growth, with ultra-high net worth individuals from across Asia showing increasing interest in premium properties.\n\nRecent transactions in exclusive areas such as Koh Pich (Diamond Island) and the Embassy District have set new price records, with luxury villas selling for between $2 million and $8 million. These properties feature world-class amenities including private pools, smart home systems, and concierge services.\n\n\"We\'re seeing a new breed of luxury buyer,\" notes Mr. Philippe Martin, Director of Knight Frank Cambodia. \"They want not just a property, but a lifestyle investment that offers privacy, security, and exceptional quality.\"\n\nThe trend extends beyond Phnom Penh, with coastal areas like Kep and the islands off Sihanoukville attracting buyers seeking exclusive beachfront estates. Several ultra-luxury resort developments are underway, targeting the growing market for vacation homes.\n\nInternational buyers, particularly from Hong Kong, Singapore, and mainland China, represent approximately 60% of luxury property purchases. They\'re attracted by Cambodia\'s relatively low property prices compared to other regional markets, favorable foreign ownership laws, and potential for capital appreciation.\n\nDevelopers are responding with increasingly sophisticated offerings, including branded residences managed by international hospitality groups and estates with private beach access.', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2477, 'App\\Models\\NewsArticle', 10, 'km', 'title', 'Luxury Villa Market Attracts Ultra-High Net Worth Buyers (ខ្មែរ)', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2478, 'App\\Models\\NewsArticle', 10, 'km', 'category', 'Luxury Real Estate', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
