(2537, 'App\\Models\\NewsArticle', 14, 'en', 'title', 'REITs Introduction Could Transform Cambodia Investment Landscape', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2538, 'App\\Models\\NewsArticle', 14, 'en', 'category', 'Investment', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2539, 'App\\Models\\NewsArticle', 14, 'en', 'excerpt', 'Securities regulator drafts framework for Real Estate Investment Trusts. Market participants optimistic about new investment vehicle for retail investors.', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2540, 'App\\Models\\NewsArticle', 14, 'en', 'content', 'The Securities and Exchange Regulator of Cambodia (SERC) has released a draft regulatory framework for Real Estate Investment Trusts (REITs), potentially opening a new chapter in the country\'s capital markets and property sector.\n\nThe proposed framework would allow property companies to list REITs on the Cambodia Securities Exchange, providing retail investors with access to real estate investments previously available only to institutional and high-net-worth individuals.\n\n\"REITs will democratize real estate investment in Cambodia,\" explains Dr. Sou Socheat, Director-General of SERC. \"They will provide liquidity to the property market while offering investors a transparent, regulated investment vehicle with attractive dividend yields.\"\n\nThe framework includes provisions for different types of REITs, including those focused on commercial, residential, and industrial properties. Minimum dividend distribution requirements of 90% of net income are proposed to ensure attractive returns for investors.\n\nMajor property developers have expressed strong interest, with several already preparing potential REIT listings. Analysts estimate the Cambodian REIT market could reach $2 billion in assets under management within five years of launch.\n\nThe introduction of REITs is expected to attract more institutional investment into Cambodia\'s property sector, improve market transparency, and provide developers with alternative funding sources for new projects.\n\nPublic consultation on the framework continues until the end of the year, with the first REIT listings potentially possible by mid-2026.', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2541, 'App\\Models\\NewsArticle', 14, 'km', 'title', 'REITs Introduction Could Transform Cambodia Investment Landscape (ខ្មែរ)', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2542, 'App\\Models\\NewsArticle', 14, 'km', 'category', 'Investment', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2543, 'App\\Models\\NewsArticle', 14, 'km', 'excerpt', 'Securities regulator drafts framework for Real Estate Investment Trusts. Market participants optimistic about new investment vehicle for retail investors. [សង្ខេបជាភាសាខ្មែរ]', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2544, 'App\\Models\\NewsArticle', 14, 'km', 'content', 'The Securities and Exchange Regulator of Cambodia (SERC) has released a draft regulatory framework for Real Estate Investment Trusts (REITs), potentially opening a new chapter in the country\'s capital markets and property sector.\n\nThe proposed framework would allow property companies to list REITs on the Cambodia Securities Exchange, providing retail investors with access to real estate investments previously available only to institutional and high-net-worth individuals.\n\n\"REITs will democratize real estate investment in Cambodia,\" explains Dr. Sou Socheat, Director-General of SERC. \"They will provide liquidity to the property market while offering investors a transparent, regulated investment vehicle with attractive dividend yields.\"\n\nThe framework includes provisions for different types of REITs, including those focused on commercial, residential, and industrial properties. Minimum dividend distribution requirements of 90% of net income are proposed to ensure attractive returns for investors.\n\nMajor property developers have expressed strong interest, with several already preparing potential REIT listings. Analysts estimate the Cambodian REIT market could reach $2 billion in assets under management within five years of launch.\n\nThe introduction of REITs is expected to attract more institutional investment into Cambodia\'s property sector, improve market transparency, and provide developers with alternative funding sources for new projects.\n\nPublic consultation on the framework continues until the end of the year, with the first REIT listings potentially possible by mid-2026.\n\n[មាតិកាពេញលេញជាភាសាខ្មែរ]', '2025-11-29 07:36:40', '2025-11-29 07:36:40'),
(2545, 'App\\Models\\NewsArticle', 14, 'zh', 'title', 'REITs Introduction Could Transform Cambodia Investment Landscape (中文)', '2025-11-29 07:36:40', '2025-11-29 07:36:40');
